CREATE TABLE users (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,name VARCHAR(150) NOT NULL,email VARCHAR(180) NOT NULL UNIQUE,password VARCHAR(255) NOT NULL,role VARCHAR(30) NOT NULL,active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE horse (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,code VARCHAR(60) NOT NULL UNIQUE,name VARCHAR(120) NOT NULL,birth_date DATE,breed VARCHAR(120) NOT NULL,sex VARCHAR(20) NOT NULL,weight DOUBLE PRECISION,photo_url VARCHAR(500),active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE employee (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,name VARCHAR(150) NOT NULL,role VARCHAR(40) NOT NULL,contact VARCHAR(180) NOT NULL,shift VARCHAR(100),tasks TEXT,active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE medical_record (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,horse_id BIGINT NOT NULL REFERENCES horse(id),date DATE NOT NULL,type VARCHAR(50) NOT NULL,description TEXT NOT NULL,responsible VARCHAR(150) NOT NULL,next_due_date DATE,observations TEXT);
CREATE TABLE reservation (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,horse_id BIGINT NOT NULL REFERENCES horse(id),start_at TIMESTAMP NOT NULL,end_at TIMESTAMP NOT NULL,activity_type VARCHAR(50) NOT NULL,responsible VARCHAR(150) NOT NULL,status VARCHAR(30) NOT NULL,observations TEXT,capacity INTEGER NOT NULL DEFAULT 1,participants INTEGER NOT NULL DEFAULT 1,CONSTRAINT reservation_valid_interval CHECK(end_at>start_at),CONSTRAINT reservation_valid_capacity CHECK(capacity>=1 AND participants>=1 AND participants<=capacity));
CREATE TABLE inventory_item (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,name VARCHAR(150) NOT NULL UNIQUE,category VARCHAR(80) NOT NULL,quantity DOUBLE PRECISION NOT NULL CHECK(quantity>=0),minimum_stock DOUBLE PRECISION NOT NULL CHECK(minimum_stock>=0),unit VARCHAR(40) NOT NULL);
CREATE TABLE feeding_plan (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,horse_id BIGINT NOT NULL REFERENCES horse(id),feed_type VARCHAR(120) NOT NULL,quantity DOUBLE PRECISION NOT NULL CHECK(quantity>0),unit VARCHAR(40) NOT NULL,schedule_time TIME NOT NULL,notes TEXT);
CREATE TABLE supply_record (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,item_id BIGINT NOT NULL REFERENCES inventory_item(id),date TIMESTAMP NOT NULL,type VARCHAR(10) NOT NULL CHECK(type IN('IN','OUT')),quantity DOUBLE PRECISION NOT NULL CHECK(quantity>0),responsible VARCHAR(150) NOT NULL,notes TEXT);
CREATE TABLE notification_alert (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,reference_key VARCHAR(180) NOT NULL UNIQUE,category VARCHAR(40) NOT NULL,title VARCHAR(180) NOT NULL,message VARCHAR(700) NOT NULL,created_at TIMESTAMP NOT NULL,is_read BOOLEAN NOT NULL DEFAULT FALSE,active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE INDEX idx_medical_record_horse ON medical_record(horse_id,date);
CREATE INDEX idx_reservation_horse_time ON reservation(horse_id,start_at,end_at);
CREATE INDEX idx_feeding_plan_horse ON feeding_plan(horse_id);
CREATE INDEX idx_supply_record_date ON supply_record(date);
